from functools import lru_cache

@lru_cache(maxsize=None)
def win(n):
    if n + 1 >= 15 or n * 2 >= 15:
        return True
    if not win(n + 1):
        return True
    if not win(n * 2):
        return True
    return False

print(1 if win(7) else 2)

